/** Toggle between login and register tabs */
function setupAuthTabs() {
  const loginTab    = document.getElementById('tab-login');
  const registerTab = document.getElementById('tab-register');
  const loginPanel  = document.getElementById('panel-login');
  const regPanel    = document.getElementById('panel-register');

  function showLogin() {
    if (loginPanel)  loginPanel.classList.remove('hidden');
    if (regPanel)    regPanel.classList.add('hidden');
    if (loginTab)    loginTab.classList.add('active');
    if (registerTab) registerTab.classList.remove('active');
  }

  function showRegister() {
    if (loginPanel)  loginPanel.classList.add('hidden');
    if (regPanel)    regPanel.classList.remove('hidden');
    if (loginTab)    loginTab.classList.remove('active');
    if (registerTab) registerTab.classList.add('active');
  }

  if (loginTab)    loginTab.addEventListener('click',    showLogin);
  if (registerTab) registerTab.addEventListener('click', showRegister);

  // Also handle links inside auth panels
  const toRegisterLink = document.getElementById('link-to-register');
  const toLoginLink    = document.getElementById('link-to-login');
  if (toRegisterLink) toRegisterLink.addEventListener('click', function (e) { e.preventDefault(); showRegister(); });
  if (toLoginLink)    toLoginLink.addEventListener('click',    function (e) { e.preventDefault(); showLogin();    });
}

